// ============================================================
// NODE: Validate & Route Incoming Webhook
// PURPOSE: Verify the request is a genuine Meta webhook event,
// extract the core payload, and identify which client it belongs to.
// ============================================================

const body = $input.first().json.body;

// --- 1. Handle Meta Webhook Verification (GET request) ---
if ($input.first().json.query?.['hub.mode'] === 'subscribe') {
  return [{ json: { type: 'verification', challenge: $input.first().json.query['hub.challenge'] } }];
}

// --- 2. Validate WhatsApp Message Structure ---
if (!body?.entry?.[0]?.changes?.[0]?.value?.messages) {
  // Not a message event (could be a status update, read receipt etc.)
  return [{ json: { type: 'non_message', raw: body } }];
}

const change = body.entry[0].changes[0].value;
const message = change.messages[0];
const contact = change.contacts?.[0];

// --- 3. Extract WABA ID to identify the client ---
const wabaId = body.entry[0].id; // This is the WABA ID

// --- 4. Build normalized payload ---
return [{
  json: {
    type: 'message',
    waba_id: wabaId,
    phone_number_id: change.metadata.phone_number_id,
    message_id: message.id,
    from_phone: message.from,
    from_name: contact?.profile?.name || 'Unknown',
    message_type: message.type,
    message_text: message.text?.body || '',
    timestamp: message.timestamp,
    raw_body: body
  }
}];

// ============================================================
// NODE: Client Validation & Global Kill Switch Check
// ============================================================

const clientDocs = $input.all();
const messageData = $('🔍 Validate & Extract Payload').first().json;

// --- Check if client was found ---
if (!clientDocs || clientDocs.length === 0) {
  return [{ json: { 
    blocked: true, 
    reason: 'CLIENT_NOT_FOUND',
    waba_id: messageData.waba_id 
  }}];
}

const client = clientDocs[0].json;

// --- 1. Global Kill Switch (Platform-Level) ---
// This would be checked from system_config, but for speed we check client-level first

// --- 2. Client-Level Kill Switch ---
if (client.status?.kill_switch === true) {
  return [{ json: { 
    blocked: true, 
    reason: 'CLIENT_KILL_SWITCH',
    client_id: client.client_id,
    message_data: messageData
  }}];
}

// --- 3. Maintenance Mode ---
if (client.status?.maintenance_mode === true) {
  return [{ json: { 
    blocked: true, 
    reason: 'MAINTENANCE_MODE',
    client_id: client.client_id,
    message_data: messageData
  }}];
}

// --- 4. Subscription Expiry Check ---
const now = new Date();
const expiryDate = new Date(client.subscription?.expiry_date);
if (expiryDate < now) {
  return [{ json: { 
    blocked: true, 
    reason: 'SUBSCRIPTION_EXPIRED',
    client_id: client.client_id,
    message_data: messageData,
    expiry_date: client.subscription.expiry_date
  }}];
}

// --- 5. ALL CHECKS PASSED — proceed ---
return [{ json: {
  blocked: false,
  client: client,
  message_data: messageData
}}];

// ============================================================
// NODE: Meta Compliance Safety Filter (Guardrails)
// PURPOSE: Pre-process user message to detect and block
// sensitive topics BEFORE sending to AI model.
// ============================================================

const { client, message_data } = $input.first().json;
const text = message_data.message_text.toLowerCase();
const safetyConfig = client.safety_config;

if (!safetyConfig?.guardrails_enabled) {
  return [{ json: { safe: true, client, message_data } }];
}

// --- 1. Blocked Topics Detection (keyword-based + pattern matching) ---
const BLOCKED_PATTERNS = {
  politics: [
    /\b(سياس|انتخاب|حزب|رئيس|برلمان|ثورة|احتجاج)\b/i,
    /\b(politique|élection|parti|président|parlement|révolution)\b/i,
    /\b(politic|election|party|president|parliament|revolution|protest)\b/i
  ],
  religion: [
    /\b(دين|إسلام|مسيح|يهود|كفر|فتوى|حلال|حرام)\b/i,
    /\b(religion|islam|chrétien|juif|fatwa|halal|haram)\b/i,
    /\b(religion|islam|christian|jewish|fatwa|halal|haram|blasphemy)\b/i
  ],
  adult_content: [
    /\b(sex|nude|xxx|porn|escort)\b/i,
    /\b(جنس|عاري|بورن)\b/i
  ],
  violence: [
    /\b(bomb|weapon|kill|attack|terrorist|داعش|قنبلة|سلاح|إرهاب)\b/i,
    /\b(bombe|arme|tuer|attaque|terroriste)\b/i
  ]
};

const blockedTopics = safetyConfig.blocked_topics || [];
let detectedTopic = null;

for (const topic of blockedTopics) {
  if (BLOCKED_PATTERNS[topic]) {
    for (const pattern of BLOCKED_PATTERNS[topic]) {
      if (pattern.test(text)) {
        detectedTopic = topic;
        break;
      }
    }
  }
  if (detectedTopic) break;
}

// --- 2. Custom Blocked Words ---
const customBlocked = safetyConfig.custom_blocked_words || [];
const foundCustom = customBlocked.find(word => text.includes(word.toLowerCase()));
if (foundCustom) detectedTopic = 'custom_blocked_word';

// --- 3. Result ---
if (detectedTopic) {
  return [{ json: {
    safe: false,
    detected_topic: detectedTopic,
    client,
    message_data
  }}];
}

return [{ json: { safe: true, client, message_data } }];

// ============================================================
// NODE: Multi-Lingual Auto-Detection
// PURPOSE: Detect the user's language and apply override if set.
// ============================================================

const { client, message_data } = $input.first().json;
const text = message_data.message_text;
const aiConfig = client.ai_config;

let detectedLanguage = 'ar'; // Default fallback

// --- 1. Check Manual Override ---
if (aiConfig.language_mode === 'manual' && aiConfig.forced_language) {
  return [{ json: {
    language: aiConfig.forced_language,
    detection_method: 'manual_override',
    client,
    message_data
  }}];
}

// --- 2. Auto-Detection via Script Analysis ---
// Arabic: Unicode block U+0600 to U+06FF
const arabicPattern = /[\u0600-\u06FF]/;
// French: Common French words and accented chars
const frenchPattern = /\b(je|tu|il|nous|vous|ils|le|la|les|de|du|des|est|sont|bonjour|merci|comment|votre|notre)\b/i;
// English: Common English words
const englishPattern = /\b(i|you|he|she|we|they|the|is|are|was|were|hello|hi|thank|how|your|our|please|help)\b/i;

const arabicScore = (text.match(/[\u0600-\u06FF]/g) || []).length;
const frenchScore = (text.match(frenchPattern) || []).length;
const englishScore = (text.match(englishPattern) || []).length;

if (arabicScore > 2) {
  detectedLanguage = 'ar';
} else if (frenchScore >= englishScore) {
  detectedLanguage = frenchScore > 0 ? 'fr' : 'ar';
} else {
  detectedLanguage = englishScore > 0 ? 'en' : 'ar';
}

return [{ json: {
  language: detectedLanguage,
  detection_method: 'auto',
  scores: { arabic: arabicScore, french: frenchScore, english: englishScore },
  client,
  message_data
}}];

// ============================================================
// NODE: Build AI Prompt (System + Context + User)
// PURPOSE: Construct the full messages array for the LLM
// with client's brand voice, language instruction,
// and recent conversation history.
// ============================================================

const input = $input.first().json;
const langData = $('🌍 Language Detection').first().json;
const historyDoc = input; // Conversation history from Firebase

const client = langData.client;
const messageData = langData.message_data;
const language = langData.language;
const aiConfig = client.ai_config;

// --- 1. Language instruction suffix ---
const langInstructions = {
  ar: 'يجب أن تكون جميع ردودك باللغة العربية الفصحى أو الدارجة حسب السياق.',
  fr: 'Toutes vos réponses doivent être en français, de manière professionnelle et chaleureuse.',
  en: 'All your responses must be in English, professional and friendly.'
};

// --- 2. Build System Prompt ---
const systemPrompt = `${aiConfig.system_prompt}

--- CRITICAL LANGUAGE RULE ---
${langInstructions[language]}

--- BRAND GUIDELINES ---
Brand Name: ${aiConfig.brand_name}
Tone: ${aiConfig.brand_tone}
You are ONLY allowed to discuss topics related to this business.
NEVER reveal that you are an AI unless directly and explicitly asked.
NEVER mention competitors.
NEVER discuss politics, religion, or other sensitive topics.`;

// --- 3. Build conversation history (last 10 messages) ---
const rawHistory = historyDoc?.messages || [];
const recentHistory = rawHistory.slice(-10);
const historyMessages = recentHistory.map(msg => ({
  role: msg.role,
  content: msg.content
}));

// --- 4. Add current user message ---
const allMessages = [
  ...historyMessages,
  { role: 'user', content: messageData.message_text }
];

return [{ json: {
  system_prompt: systemPrompt,
  messages: allMessages,
  language,
  client,
  message_data: messageData,
  ai_config: aiConfig
}}];

// ============================================================
// NODE: Format & Send WhatsApp Reply
// PURPOSE: Extract AI response and send via Meta WhatsApp API.
// ============================================================

const aiResponse = $input.first().json;
const promptData = $('📝 Build AI Prompt').first().json;

const aiText = aiResponse.choices?.[0]?.message?.content || 
               'عذراً، حدث خطأ تقني. يرجى المحاولة مرة أخرى.';

const client = promptData.client;
const messageData = promptData.message_data;

// Build WhatsApp send payload
const whatsappPayload = {
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: messageData.from_phone,
  type: 'text',
  text: { body: aiText, preview_url: false }
};

return [{ json: {
  payload: whatsappPayload,
  phone_number_id: client.whatsapp_config.phone_number_id,
  access_token: client.whatsapp_config.access_token,
  ai_response: aiText,
  client,
  message_data: messageData
}}];

// Save message to Firebase conversation history + update analytics
const sendResult = $input.first().json;
const prepData = $('💬 Prepare WhatsApp Reply').first().json;

const docId = `${prepData.client.client_id}_${prepData.message_data.from_phone}`;

return [{ json: {
  document_id: docId,
  user_message: {
    role: 'user',
    content: prepData.message_data.message_text,
    timestamp: new Date().toISOString()
  },
  ai_message: {
    role: 'assistant',
    content: prepData.ai_response,
    timestamp: new Date().toISOString()
  },
  client_id: prepData.client.client_id
}}];

// Send fallback message for blocked/expired clients
const blockData = $input.first().json;
const client = blockData.client;
const messageData = blockData.message_data;

const lang = 'ar'; // Default for blocked messages

const BLOCKED_MESSAGES = {
  CLIENT_NOT_FOUND: { ar: 'عذراً، هذه الخدمة غير متاحة حالياً.', fr: 'Service non disponible.', en: 'Service not available.' },
  CLIENT_KILL_SWITCH: { ar: 'الخدمة موقوفة مؤقتاً. للمساعدة اتصل بنا.', fr: 'Service suspendu. Contactez-nous.', en: 'Service suspended. Contact us.' },
  SUBSCRIPTION_EXPIRED: { ar: 'انتهت صلاحية الاشتراك. يرجى التجديد.', fr: 'Abonnement expiré. Veuillez renouveler.', en: 'Subscription expired. Please renew.' },
  MAINTENANCE_MODE: { ar: 'الخدمة تحت الصيانة. نعود قريباً.', fr: 'Maintenance en cours. Revenez bientôt.', en: 'Under maintenance. Back soon.' }
};

const msg = BLOCKED_MESSAGES[blockData.reason]?.[lang] || 'خدمة غير متاحة.';

return [{ json: {
  payload: {
    messaging_product: 'whatsapp',
    to: messageData?.from_phone,
    type: 'text',
    text: { body: msg }
  },
  phone_number_id: client?.whatsapp_config?.phone_number_id,
  access_token: client?.whatsapp_config?.access_token,
  reason: blockData.reason
}}];

// Check which clients expire within 48 hours
const clients = $input.all();
const now = new Date();
const in48h = new Date(now.getTime() + 48 * 60 * 60 * 1000);

const expiring = clients.filter(c => {
  const expiry = new Date(c.json.subscription?.expiry_date);
  return expiry > now && expiry <= in48h;
});

return expiring.map(c => ({ json: c.json }));
